// // This module implements an 8-bit register with synchronous load and clear signals.
// The register loads new data on the falling edge of the clock signal when the load signal is low.
// When the clear signal is low, the register resets to zero on the falling edge of the clock signal.
module reg_8bit_sync (
    input clk,
    input rst_n,
    input load,
    input clear,
    input [7:0] data_in,
    output reg [7:0] data_out
);

always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
        data_out <= 8'b00000000;
    else if (clear)
        data_out <= 8'b00000000;
    else if (load)
        data_out <= data_in;
end

endmodule

